  "inlineSchema": "// schema.prisma — Agenda Digital para Creches\n// Stack: PostgreSQL + Prisma v5\n//\n// Decisões travadas:\n//  - \"Recados\" e \"feed\" = MESMA entidade (Publicacao com tipo). Feed é só a visão filtrada.\n//  - Um aluno pode ter VÁRIOS responsáveis (M2M via join explícito ResponsavelAluno).\n//  - Um usuário só, com campo `papel` (mesma abordagem de single-table + role).\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ==================== ENUMS ====================\n\nenum Papel {\n  RESPONSAVEL\n  PROFESSOR\n  ADMIN\n}\n\nenum TipoPublicacao {\n  GERAL // pra creche inteira\n  TURMA // pra uma turma específica  -> preenche turmaId\n  INDIVIDUAL // pra um aluno específico  -> preenche alunoId\n}\n\n// enums do diário = valores de seleção rápida no form pré-setado\nenum HumorDia {\n  OTIMO\n  BOM\n  AGITADO\n  CHOROSO\n  ADOECIDO\n}\n\nenum QuantidadeRefeicao {\n  TUDO\n  METADE\n  POUCO\n  RECUSOU\n  NAO_SE_APLICA\n}\n\nenum QualidadeSono {\n  DORMIU_BEM\n  DORMIU_POUCO\n  AGITADO\n  NAO_DORMIU\n}\n\n// ==================== USUÁRIO ====================\n// Um só model de usuário, diferenciado pelo `papel`.\n// As relações abaixo só fazem sentido conforme o papel:\n//  - PROFESSOR usa: turmas, publicacoes, registrosDiario\n//  - RESPONSAVEL usa: alunos (via ResponsavelAluno)\n\nmodel Usuario {\n  id        String   @id @default(uuid())\n  nome      String\n  email     String   @unique\n  senhaHash String\n  papel     Papel\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // se PROFESSOR:\n  turmas          Turma[]          @relation(\"ProfessorTurmas\") // M2M\n  publicacoes     Publicacao[] // publicações que ele criou (autor)\n  registrosDiario RegistroDiario[] // diários que ele preencheu\n\n  // se RESPONSAVEL:\n  alunos ResponsavelAluno[]\n}\n\n// ==================== TURMA ====================\n\nmodel Turma {\n  id        String   @id @default(uuid())\n  nome      String // ex: \"Berçário II\", \"Maternal I\"\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  professores Usuario[]    @relation(\"ProfessorTurmas\") // M2M (assumido)\n  alunos      Aluno[]\n  publicacoes Publicacao[] // publicações do tipo TURMA\n}\n\n// ==================== ALUNO ====================\n\nmodel Aluno {\n  id             String   @id @default(uuid())\n  nome           String\n  dataNascimento DateTime\n  // perfil básico:\n  alergias       String? // texto livre por ora\n  observacoes    String? // cuidados especiais, restrições...\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  turmaId String\n  turma   Turma  @relation(fields: [turmaId], references: [id], onDelete: NoAction)\n\n  responsaveis    ResponsavelAluno[]\n  publicacoes     Publicacao[] // publicações do tipo INDIVIDUAL\n  registrosDiario RegistroDiario[]\n}\n\n// Join explícito Responsável <-> Aluno (M2M).\n// Explícito (não implícito) pra poder guardar o parentesco.\nmodel ResponsavelAluno {\n  id            String  @id @default(uuid())\n  responsavelId String\n  alunoId       String\n  parentesco    String? // \"mãe\", \"pai\", \"avó\"... opcional\n\n  responsavel Usuario @relation(fields: [responsavelId], references: [id], onDelete: NoAction)\n  aluno       Aluno   @relation(fields: [alunoId], references: [id], onDelete: NoAction)\n\n  @@unique([responsavelId, alunoId]) // evita vínculo duplicado\n}\n\n// ==================== PUBLICAÇÃO (recados + feed unificados) ====================\n// A consistência tipo<->campo (TURMA exige turmaId, INDIVIDUAL exige alunoId,\n// GERAL não exige nenhum) NÃO dá pra travar 100% no schema — isso a gente\n// valida no controller na hora de criar.\n\nmodel Publicacao {\n  id        String         @id @default(uuid())\n  tipo      TipoPublicacao\n  conteudo  String\n  createdAt DateTime       @default(now())\n  updatedAt DateTime       @updatedAt\n\n  // autor = professor (ou admin)\n  autorId String\n  autor   Usuario @relation(fields: [autorId], references: [id], onDelete: NoAction)\n\n  // só quando tipo = TURMA\n  turmaId String?\n  turma   Turma?  @relation(fields: [turmaId], references: [id])\n\n  // só quando tipo = INDIVIDUAL\n  alunoId String?\n  aluno   Aluno?  @relation(fields: [alunoId], references: [id])\n}\n\n// ==================== REGISTRO DIÁRIO (o form pré-setado) ====================\n// 1 registro por aluno por dia (por isso @db.Date + @@unique).\n\nmodel RegistroDiario {\n  id   String   @id @default(uuid())\n  data DateTime @db.Date // só a data (sem hora) -> permite \"1 por dia\"\n\n  humor HumorDia\n\n  // alimentação por refeição = seleção rápida\n  cafe   QuantidadeRefeicao @default(NAO_SE_APLICA)\n  almoco QuantidadeRefeicao @default(NAO_SE_APLICA)\n  lanche QuantidadeRefeicao @default(NAO_SE_APLICA)\n\n  sono QualidadeSono\n\n  trocasFralda Int? // nº de trocas (útil no berçário)\n  evacuou      Boolean?\n\n  atividades           String? // o que fez no dia\n  materiaisNecessarios String? // \"acabando fralda / lenço umedecido\"\n  observacoes          String? // qualquer coisa extra pro responsável\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  alunoId String\n  aluno   Aluno  @relation(fields: [alunoId], references: [id], onDelete: NoAction)\n\n  professorId String\n  professor   Usuario @relation(fields: [professorId], references: [id], onDelete: NoAction)\n\n  @@unique([alunoId, data]) // um registro por aluno por dia\n}\n",
  "inlineSchemaHash": "01d8b5548cb77dbafba5b63ab56a028a7ee72a18ecdaf717c772b6bc73a564f5",
